    const logType = params.logType || 'oak_log';
    // 1. 寻找附近的原木
    const logs = bot.findNearbyBlocks(logType, 32, 10);
    if (logs.length === 0) {
        bot.chat(`附近没有找到 ${logType} 原木，开始探索寻找。`);
